msg.payload = `SELECT
    enc.CONSTANCIA          AS nro_constancia,
    CAST(enc.ID AS varchar(36)) AS id_constancia,
    enc.FECHAACTUAL,
    enc.DETALLE             AS detalle_interno,
    enc.subtotal_doc,
    enc.totalConstancia,
    enc.monConstancia,
    enc.nom_proveedor,
    (SELECT TOP 1 ISNULL(d.NOM_PRODUCTO,'') + CASE WHEN ISNULL(d.MEMO,'') <> '' THEN ' — ' + d.MEMO ELSE '' END
     FROM V_EZI_PROV_CONST_SC_DET d
     WHERE d.constancia = enc.CONSTANCIA
     ORDER BY d.NUMEROITEM) AS descripcion,
    (SELECT TOP 1 cf.NUMEROFAC
     FROM V_EZI_CONSTANCIA_FACTURA cf
     WHERE cf.ID_CONST = enc.ID) AS factura_existente,
    (SELECT TOP 1 cf.IMPORTEFACT
     FROM V_EZI_CONSTANCIA_FACTURA cf
     WHERE cf.ID_CONST = enc.ID) AS importe_factura_existente
FROM V_EZI_PROV_CONST_SC_ENC enc
WHERE enc.numeroOC = '${oc}'
ORDER BY enc.FECHAACTUAL DESC`;
return [msg, null];

