msg._res = msg.res;
const q = (msg.req.query.q || '').replace(/[^a-zA-Z0-9 ]/g, '');
if (!q || q.length < 2) { msg.payload = JSON.stringify([]); return msg; }
msg.payload = `SELECT TOP 20 ID, CODIGO, DENOMINACION AS nombre, CUIT AS cuit
FROM PROVEEDOR
WHERE ACTIVESTATUS = 0
  AND (DENOMINACION LIKE '%${q}%' OR CUIT LIKE '%${q}%' OR CODIGO LIKE '%${q}%')
ORDER BY DENOMINACION`;
return msg;

msg.res = msg._res;
msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
