msg._res = msg.res;
const cuit = (msg.req.params.cuit || '').replace(/[^0-9]/g, '');
if (!cuit) {
  msg.statusCode = 400;
  msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
  msg.payload = JSON.stringify({ error: 'CUIT requerido' });
  return [null, msg];
}
msg.payload = `SELECT
    oc.ID AS id,
    oc.NUMERODOCUMENTO AS nro,
    CONVERT(varchar, oc.FECHAINGRESO, 112) AS fecha,
    oc.TOTAL AS total,
    oc.ESTADO AS estado,
    CASE WHEN EXISTS (SELECT 1 FROM TRFACTURACOMPRA fc WHERE fc.DETALLE = oc.NUMERODOCUMENTO) THEN 1 ELSE 0 END AS facturada
FROM TRORDENCOMPRA oc
JOIN PROVEEDOR p ON p.CODIGO = oc.CODIGODESTINATARIO
WHERE p.CUIT = '${cuit}' AND oc.ESTADO IN ('A','P','C')
ORDER BY oc.FECHAINGRESO DESC`;
return [msg, null];

msg.res = msg._res;
msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
msg.payload = JSON.stringify(msg.payload || []);
return msg;

msg._req = msg.req;
msg._res = msg.res;
const hash = (msg.req.query.hash || '').replace(/[^a-fA-F0-9]/g, '');
const doc  = (msg.req.query.doc  || '').replace(/[^0-9\-]/g, '');
const cuit = (msg.req.query.cuit || '').replace(/[^0-9]/g, '');
let where = '1=0';
if (hash) where = `PDF_HASH = '${hash}'`;
else if (doc && cuit) where = `NUMERODOCUMENTO = '${doc}' AND PROVEEDOR_CUIT = '${cuit}'`;
msg.payload = `SELECT TOP 1 ID FROM UD_EZI_STAGING_FACTURAS WHERE ${where}`;
return msg;

msg.res = msg._res;
msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
const rows = msg.payload || [];
msg.payload = JSON.stringify({ existe: rows.length > 0, encontrados: rows.length });
return msg;

// Campos que n8n envía en el POST
const q = msg.req.body || {};

// Validar campos requeridos
if (!q.staging_id || !q.sql_query) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = JSON.stringify({ ok: false, error: 'Faltan staging_id o sql_query' });
    return [null, msg];
}

msg._factura = {
    staging_id:     q.staging_id,
    cuit:           q.cuit          || '',
    razon_social:   q.razon_social  || '',
    nro_documento:  q.nro_documento || '',
    letra:          q.letra         || 'A',
    fecha_emision:  q.fecha_emision || '',
    total:          q.total         || '0',
    tipo_operacion: q.tipo_operacion|| 'FACTURA_COMPRA',
    confianza:      q.confianza_parseo || '',
    sql_query:      q.sql_query,
    items_json:     q.items_json    || '[]',
    pdf_hash:       q.pdf_hash      || '',
    file_type:      q.file_type     || 'pdf'
};

// MSSQL: query via msg.payload
msg.payload = q.sql_query;
return [msg, null];

const f = msg._factura;
let items = [];
try { items = JSON.parse(f.items_json || '[]'); } catch(e) { items = []; }
if (!items || items.length === 0) return [null, msg];
const esc = s => s ? String(s).replace(/'/g, "''") : '';
const rows = items.map(it => {
    const desc = esc(it.descripcion || '');
    const cant = (it.cantidad != null) ? Number(it.cantidad) : 'NULL';
    const uni  = esc(it.unidad || 'u');
    const pu   = (it.precio_unitario != null) ? Number(it.precio_unitario) : 'NULL';
    const aliq = (it.alicuota_iva != null) ? parseInt(it.alicuota_iva) : 'NULL';
    const sub  = (it.subtotal != null) ? Number(it.subtotal) : 'NULL';
    const lin  = parseInt(it.linea) || 1;
    return `('${f.staging_id}', ${lin}, '${desc}', ${cant}, '${uni}', ${pu}, ${aliq}, ${sub})`;
}).join(',\n');
msg.payload = `INSERT INTO UD_EZI_STAGING_ITEMS (FACTURA_ID, LINEA, DESCRIPCION, CANTIDAD, UNIDAD, PRECIO_UNITARIO, ALICUOTA_IVA, SUBTOTAL) VALUES\n${rows}`;
return [msg, null];

const f = msg._factura || {};
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({
    ok: true,
    staging_id:    f.staging_id,
    razon_social:  f.razon_social,
    nro_documento: f.nro_documento,
    total:         f.total,
    mensaje:       'Factura registrada en staging (SQL Server)'
});
return msg;

const f = msg._factura || {};
node.error('Error SQL Server [' + f.staging_id + ']: ' + (msg.error && msg.error.message));
msg.statusCode = 500;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({
    ok: false, staging_id: f.staging_id,
    error: (msg.error && msg.error.message) || 'Error en SQL Server'
});
return msg;
